<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('projects.view');$phase=vp3_input('phase');$sql='SELECT p.*,c.name customer_name,a.name manager_name,(SELECT COUNT(*) FROM project_tasks t WHERE t.project_id=p.id AND t.status NOT IN (\'completed\',\'cancelled\')) open_tasks,(SELECT COUNT(*) FROM project_approvals pa WHERE pa.project_id=p.id AND pa.status=\'pending\') pending_approvals FROM creative_projects p JOIN customers c ON c.id=p.customer_id LEFT JOIN admins a ON a.id=p.project_manager_admin_id WHERE 1=1';$params=[];if($phase!==''){$sql.=' AND p.phase=?';$params[]=$phase;}$sql.=' ORDER BY FIELD(p.health_status,\'blocked\',\'at_risk\',\'on_track\',\'complete\'),p.target_launch_date,p.updated_at DESC LIMIT 250';$rows=[];try{$stmt=vp3_db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();}catch(Throwable){}$pageTitle='Creative Projects';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Client delivery</span><h1>Creative projects</h1><p>Manage discovery, strategy, production, launch readiness, customer action, and delivery risk.</p></div><a class="button" href="project.php">Create project</a></div><form class="admin-filter"><label>Phase<select name="phase"><option value="">All phases</option><?php foreach(['discovery','strategy','development','production','launch','active','paused','completed','cancelled'] as $v):?><option <?=$phase===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><button class="button small">Filter</button></form><div class="project-grid admin-project-grid"><?php foreach($rows as $p):?><article class="project-card"><div class="project-card-top"><span class="badge <?=vp3_e($p['health_status'])?>"><?=vp3_e(str_replace('_',' ',$p['health_status']))?></span><span><?=vp3_e(vp3_project_phase_label($p['phase']))?></span></div><h2><a href="project.php?id=<?=(int)$p['id']?>"><?=vp3_e($p['title'])?></a></h2><p><?=vp3_e($p['customer_name'].' · '.($p['manager_name']?:'Unassigned'))?></p><div class="readiness"><div><span>Readiness</span><strong><?=(int)$p['readiness_percent']?>%</strong></div><i><b style="width:<?=(int)$p['readiness_percent']?>%"></b></i></div><dl class="mini-metrics"><div><dt>Tasks</dt><dd><?=(int)$p['open_tasks']?></dd></div><div><dt>Approvals</dt><dd><?=(int)$p['pending_approvals']?></dd></div><div><dt>Launch</dt><dd><?=vp3_e($p['target_launch_date']?:'—')?></dd></div></dl></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><p>No projects yet.</p></div><?php endif;?></div>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
